+struct RecentPullRequestFiltersView: View {
+    @Bindable var session: Session
+
+    var body: some View {
+        HStack(spacing: 6) {
+            Picker("Scope", selection: self.$session.recentPullRequestScope) {
+                ForEach(RecentPullRequestScope.allCases, id: \.self) { scope in
